        e.preventDefault()
        console.log('ontimeout', e)
        uploadError(dispatch, 'Timeout')
        return false
      }
    request.onerror =
      (e) => {
        e.preventDefault()
        console.log('onerror', e)
        uploadError(dispatch, e)
        return false
      }
    request.onabort =
      (e) => {
        e.preventDefault()
        console.log('onabort', e)
        //alert(e)
        uploadError(dispatch, 'Aborted')
        return false
      }

    //console.log("postin", url)
